import streamlit as stfrom streamlit_gsheets import GSheetsConnectionimport pandas as pdfrom datetime import datetime, timedeltaimport urllib.parseimport plotly.express as pximport warnings# Gereksiz uyarıları gizlewarnings.filterwarnings("ignore")# --- 1. SAYFA AYARLARI ---st.set_page_config(    page_title="Bostanlı Çözüm VIP",     layout="wide",     page_icon="🏫",    initial_sidebar_state="collapsed" )# Tasarım (CSS)st.markdown("""    <style>    #MainMenu {visibility: hidden;}    footer {visibility: hidden;}    header {visibility: hidden;}    .stDeployButton {display:none;}    .stTabs [data-baseweb="tab-list"] {        gap: 15px;        background-color: #f0f2f6;        padding: 10px;        border-radius: 10px;    }    .stTabs [data-baseweb="tab"] {        height: 50px;        background-color: #ffffff;        border-radius: 5px;        font-weight: bold;    }    </style>    """, unsafe_allow_html=True)# --- 2. ŞİFRE SİSTEMİ ---def check_password():    if "user_role" not in st.session_state:        st.title("🔐 Kurumsal Yönetim Paneli")        pwd = st.text_input("Giriş Şifresi", type="password")        if st.button("Sisteme Giriş Yap"):            if pwd == "cozum35":                st.session_state["user_role"] = "admin"                st.rerun()            elif pwd == "personel35":                st.session_state["user_role"] = "staff"                st.rerun()            else:                st.error("❌ Hatalı şifre.")        return False    return Trueif check_password():    conn = st.connection("gsheets", type=GSheetsConnection)    role = st.session_state["user_role"]    def wa_link(tel, mesaj):        tel_str = str(tel).replace(" ", "").replace("-", "").replace("(", "").replace(")", "")        if tel_str.startswith("0"): tel_str = "90" + tel_str[1:]        elif not tel_str.startswith("90"): tel_str = "90" + tel_str        return f"https://wa.me/{tel_str}?text={urllib.parse.quote(mesaj)}"    # Üst Başlık ve Çıkış    c_title, c_exit = st.columns([4, 1])    with c_title:        st.title(f"🏫 Bostanlı Çözüm VIP ({'Kurucu' if role == 'admin' else 'Personel'} Paneli)")    with c_exit:        if st.button("🚪 Güvenli Çıkış"):            del st.session_state["user_role"]            st.rerun()    # --- 3. SEKMELER ---    if role == "admin":        tabs = st.tabs(["📊 Kurucu Raporu", "📈 Gelişmiş Analiz"])    else:        tabs = st.tabs(["📞 Veli Görüşmeleri", "💰 Kasa İşlemleri", "🚨 Günlük Olaylar", "📝 Raporu İlet"])    # --- VERİ YÜKLEME FONKSİYONU ---    def load_all_data(target_date_str):        try:            dv = conn.read(worksheet="gorusmeler", ttl=0)            dk = conn.read(worksheet="kasa", ttl=0)            do = conn.read(worksheet="olaylar", ttl=0)                        dv_b = dv[dv['Tarih'].astype(str).str.contains(target_date_str, na=False)]            dk_b = dk[dk['Tarih'].astype(str).str.contains(target_date_str, na=False)]            do_b = do[do['Tarih'].astype(str).str.contains(target_date_str, na=False)]                        dk_b['Miktar'] = pd.to_numeric(dk_b['Miktar'], errors='coerce').fillna(0)            gelir_df = dk_b[dk_b['Tip'] == 'Gelir (Tahsilat)']            gider_df = dk_b[dk_b['Tip'] == 'Gider (Ödeme)']                        return {"dv_b": dv_b, "gelir_df": gelir_df, "gider_df": gider_df, "do_b": do_b,                     "t_gelir": gelir_df['Miktar'].sum(), "t_gider": gider_df['Miktar'].sum()}        except: return None    # --- 🔵 KURUCU PANELİ ---    if role == "admin":        with tabs[0]: # KURUCU RAPORU            st.header("📊 Günlük Durum Özeti")            t_sec_raw = st.date_input("Rapor Tarihi", datetime.now(), format="DD/MM/YYYY")            res = load_all_data(t_sec_raw.strftime("%Y-%m-%d"))            if res:                m1, m2, m3, m4 = st.columns(4)                m1.metric("Görüşme", len(res["dv_b"]))                m2.metric("Gelir", f"{res['t_gelir']:,.0f} TL")                m3.metric("Gider", f"{res['t_gider']:,.0f} TL")                m4.metric("Net", f"{res['t_gelir'] - res['t_gider']:,.0f} TL")                st.subheader("📞 Bugün Yapılan Görüşmeler")                st.dataframe(res["dv_b"][['Veli Ad Soyad', 'Öğrenci Ad Soyad', 'Konu', 'Durum']], use_container_width=True)        with tabs[1]: # GELİŞMİŞ ANALİZ            st.header("📈 Finansal & Operasyonel Analiz")                        # Verileri çek            df_kasa = conn.read(worksheet="kasa", ttl=0)            df_gorus = conn.read(worksheet="gorusmeler", ttl=0)                        # Tarih Filtresi            c_a, c_b = st.columns(2)            start_date = c_a.date_input("Analiz Başlangıç", datetime.now() - timedelta(days=30))            end_date = c_b.date_input("Analiz Bitiş", datetime.now())                        # Kasa Veri Hazırlama            df_kasa['Tarih'] = pd.to_datetime(df_kasa['Tarih'])            df_kasa['Miktar'] = pd.to_numeric(df_kasa['Miktar'], errors='coerce').fillna(0)            df_f_kasa = df_kasa[(df_kasa['Tarih'].dt.date >= start_date) & (df_kasa['Tarih'].dt.date <= end_date)]                        # Görüşme Veri Hazırlama            df_gorus['Tarih'] = pd.to_datetime(df_gorus['Tarih'])            df_f_gorus = df_gorus[(df_gorus['Tarih'].dt.date >= start_date) & (df_gorus['Tarih'].dt.date <= end_date)]            # GÖRSELLEŞTİRME - SATIR 1: FİNANS            st.subheader("💰 Finansal Dağılım")            col1, col2 = st.columns(2)            with col1:                fig_gelir = px.pie(df_f_kasa[df_f_kasa['Tip'] == 'Gelir (Tahsilat)'], values='Miktar', names='Kategori', title="Gelir Kaynakları", hole=0.4)                st.plotly_chart(fig_gelir, use_container_width=True)            with col2:                fig_gider = px.pie(df_f_kasa[df_f_kasa['Tip'] == 'Gider (Ödeme)'], values='Miktar', names='Kategori', title="Gider Dağılımı", hole=0.4)                st.plotly_chart(fig_gider, use_container_width=True)            # GÖRSELLEŞTİRME - SATIR 2: GÖRÜŞME ANALİZİ            st.divider()            st.subheader("📞 Görüşme Performansı (Dönüşüm)")            col3, col4 = st.columns(2)            with col3:                # Durum Dağılımı (Olumlu, Olumsuz, Beklemede...)                status_counts = df_f_gorus['Durum'].value_counts().reset_index()                status_counts.columns = ['Durum', 'Sayı']                fig_status = px.bar(status_counts, x='Durum', y='Sayı', color='Durum', title="Görüşme Sonuçları Dağılımı", text_auto=True)                st.plotly_chart(fig_status, use_container_width=True)            with col4:                # Konu Dağılımı (YKS, LGS, Kamp...)                topic_counts = df_f_gorus['Konu'].value_counts().reset_index()                topic_counts.columns = ['Konu', 'Sayı']                fig_topic = px.pie(topic_counts, values='Sayı', names='Konu', title="Başvuru Yapılan Kategoriler", hole=0.4)                st.plotly_chart(fig_topic, use_container_width=True)            # GÖRSELLEŞTİRME - SATIR 3: ZAMAN ÇİZELGESİ            st.divider()            st.subheader("📅 Zaman Bazlı Hareket")            # Günlük Görüşme Sayısı Grafiği            daily_g = df_f_gorus.groupby(df_f_gorus['Tarih'].dt.date).size().reset_index(name='Görüşme Sayısı')            fig_line = px.line(daily_g, x='Tarih', y='Görüşme Sayısı', title="Günlük Görüşme Trafiği", markers=True)            st.plotly_chart(fig_line, use_container_width=True)    # --- 🟢 PERSONEL PANELİ ---    else:        # (Personel sekmeleri: Görüşme Kayıt, Kasa Kayıt, Olay Kayıt, Rapor Gönder - V31'deki gibi devam eder)        with tabs[0]: # Görüşme Kayıt            st.header("📞 Veli Görüşme Kayıt")            df_v = conn.read(worksheet="gorusmeler", ttl=0)            with st.form("v_form", clear_on_submit=True):                v_t = st.date_input("Tarih", datetime.now())                c1, c2 = st.columns(2)                v_a = c1.text_input("Veli Ad Soyad")                o_a = c1.text_input("Öğrenci Ad Soyad")                v_tel = c2.text_input("Telefon")                v_ko = c2.selectbox("Konu", ["Seçiniz...", "YKS Hazırlık", "LGS Hazırlık", "Ara Sınıf", "Kamp", "Diğer"])                v_du = st.selectbox("Durum", ["Beklemede", "Olumlu", "Olumsuz", "Kayıt Tamamlandı", "İptal"])                v_no = st.text_area("Notlar")                if st.form_submit_button("Kaydet"):                    new = pd.DataFrame([{"Tarih": v_t.strftime("%Y-%m-%d"), "Veli Ad Soyad": v_a, "Öğrenci Ad Soyad": o_a, "Telefon": v_tel, "Konu": v_ko, "Durum": v_du, "Notlar": v_no}])                    conn.update(worksheet="gorusmeler", data=pd.concat([df_v, new], ignore_index=True))                    st.success("Kaydedildi!")            st.subheader("🔍 Kayıtları Düzenle")            st.data_editor(df_v, num_rows="dynamic", key="v_edit")            if st.button("Görüşmeleri Güncelle"): conn.update(worksheet="gorusmeler", data=st.session_state.v_edit)        with tabs[1]: # Kasa Kayıt            st.header("💰 Kasa İşlemleri")            df_k = conn.read(worksheet="kasa", ttl=0)            # ... Kasa form ve editor kodları ...            st.data_editor(df_k, num_rows="dynamic", key="k_edit")            if st.button("Kasayı Güncelle"): conn.update(worksheet="kasa", data=st.session_state.k_edit)        with tabs[2]: # Olay Kayıt            st.header("🚨 Olaylar")            # ... Olay kayıt kodları ...        with tabs[3]: # Rapor Gönder            st.header("📝 Rapor İlet")            # ... Rapor gönderim kodları ...